import{_ as t,o as a,c as o,ag as s}from"./chunks/framework.BYehg5q7.js";const u=JSON.parse('{"title":"Architecture Roadmap","description":"","frontmatter":{},"headers":[],"relativePath":"plans/tauri-monorepo.md","filePath":"plans/tauri-monorepo.md","lastUpdated":null}'),i={name:"plans/tauri-monorepo.md"};function r(l,e,n,d,c,p){return a(),o("div",null,[...e[0]||(e[0]=[s(`<h1 id="architecture-roadmap" tabindex="-1">Architecture Roadmap <a class="header-anchor" href="#architecture-roadmap" aria-label="Permalink to &quot;Architecture Roadmap&quot;">​</a></h1><h2 id="current-state-v1-12-x" tabindex="-1">Current State (v1.12.x) <a class="header-anchor" href="#current-state-v1-12-x" aria-label="Permalink to &quot;Current State (v1.12.x)&quot;">​</a></h2><p>35 vanilla ES modules (~25K lines), no build tools, no framework. All data in localStorage/IndexedDB per browser. AES-256-GCM encryption at rest. PWA with service worker. CORS solved via Vercel Edge proxy (<code>api/proxy.js</code>). Cross-device sync via Evolu CRDT (E2E encrypted, self-hosted relay at sync.getbased.health). OpenClaw context gateway on relay port 4001. Current repo: <code>elkimek/get-based</code>.</p><h2 id="what-s-been-shipped" tabindex="-1">What&#39;s Been Shipped <a class="header-anchor" href="#what-s-been-shipped" aria-label="Permalink to &quot;What&#39;s Been Shipped&quot;">​</a></h2><p>The original plan assumed sync would force a build step, triggering the TS/Svelte chain. Instead, sync and OpenClaw shipped pragmatically on top of vanilla JS — proving the features without the rewrite.</p><h3 id="phase-0-openclaw-context-gateway-✅" tabindex="-1">Phase 0: OpenClaw Context Gateway ✅ <a class="header-anchor" href="#phase-0-openclaw-context-gateway-✅" aria-label="Permalink to &quot;Phase 0: OpenClaw Context Gateway ✅&quot;">​</a></h3><ul><li>Context gateway on relay (:4001) pushes <code>buildLabContext()</code> to OpenClaw</li><li>Read-only — OpenClaw reads health data, users discuss in Signal/Telegram</li><li>Shipped as part of relay infrastructure, no MCP server needed</li></ul><h3 id="phase-1-cross-device-sync-✅" tabindex="-1">Phase 1: Cross-Device Sync ✅ <a class="header-anchor" href="#phase-1-cross-device-sync-✅" aria-label="Permalink to &quot;Phase 1: Cross-Device Sync ✅&quot;">​</a></h3><ul><li>Evolu CRDT sync live (v1.9.5–1.9.8), self-hosted relay on VPS</li><li>BIP-39 mnemonic identity, E2E encrypted</li><li>Setup wizard (new/join), all profiles + AI settings synced</li><li>Data model unchanged — <code>importedData</code> serialized as blobs to Evolu (not normalized rows)</li><li>No build step introduced — Evolu vendored in <code>vendor/</code></li></ul><p><strong>What differs from the original plan:</strong> sync was bolted onto vanilla JS rather than built into a typed shared package. The data model redesign (nested arrays → normalized SQLite rows) is deferred to the v2 rewrite.</p><h2 id="v2-migration-remaining-phases" tabindex="-1">v2 Migration (Remaining Phases) <a class="header-anchor" href="#v2-migration-remaining-phases" aria-label="Permalink to &quot;v2 Migration (Remaining Phases)&quot;">​</a></h2><h3 id="new-repo-not-a-branch" tabindex="-1">New Repo, Not a Branch <a class="header-anchor" href="#new-repo-not-a-branch" aria-label="Permalink to &quot;New Repo, Not a Branch&quot;">​</a></h3><p>The v2 migration goes into a new repo (<code>get-based-v2</code> or similar), not a branch on <code>get-based</code>. Reasons:</p><ul><li>Monorepo structure is fundamentally different from the current flat layout</li><li>Build tooling (Vite, Svelte plugin, tsconfig) would pollute the current repo&#39;s &quot;no build tools&quot; identity</li><li>Current repo keeps working during migration — users, contributors, and daily driver unaffected</li><li>Bug fixes cherry-picked from <code>get-based</code> → <code>get-based-v2</code> during transition</li><li>Clean git history — no 500-commit migration branch</li></ul><p>When v2 is ready: archive <code>get-based</code>, rename <code>get-based-v2</code> → <code>get-based</code>.</p><h3 id="phase-2-project-scaffold-shared-layer-3-5-sessions" tabindex="-1">Phase 2: Project Scaffold + Shared Layer (3-5 sessions) <a class="header-anchor" href="#phase-2-project-scaffold-shared-layer-3-5-sessions" aria-label="Permalink to &quot;Phase 2: Project Scaffold + Shared Layer (3-5 sessions)&quot;">​</a></h3><p>New repo. Extract logic from vanilla JS into typed packages.</p><ul><li><strong>2a: Project scaffold</strong> — monorepo structure, Vite, tsconfig, SvelteKit skeleton</li><li><strong>2b: Extract shared layer</strong> — schema, constants, data pipeline, API layer → <code>packages/shared</code> as TypeScript. Pure logic, no DOM — safest to migrate first</li><li><strong>2c: Evolu data model redesign</strong> — <code>importedData</code> nested object → normalized SQLite rows (<code>profile_id, category, marker, date, value</code>). Migration path from v1 blob format. This is the biggest technical risk. The normalized model also unblocks two open issues that are structural limitations of v1&#39;s blob/array model: <ul><li><strong>#39</strong> (keep PDF imports separate): v1 merges all markers by date — no provenance tracking. Normalized rows get a <code>source</code> column (filename, import timestamp), enabling selective deletion per import</li><li><strong>#57</strong> (move markers between categories): v1 marker keys embed the category (<code>biochemistry.glucose</code>), so moving a marker breaks all data references. Normalized model stores category as a column on the marker definition — reassignment is a simple update without breaking value history</li></ul></li><li><strong>2d: Verify round-trip</strong> — import data, sync across devices, prove parity with v1</li></ul><h3 id="phase-3-svelte-ui-4-5-sessions" tabindex="-1">Phase 3: Svelte UI (4-5 sessions) <a class="header-anchor" href="#phase-3-svelte-ui-4-5-sessions" aria-label="Permalink to &quot;Phase 3: Svelte UI (4-5 sessions)&quot;">​</a></h3><p>Module-by-module migration using DevTools MCP for visual QA.</p><p><strong>Migration order</strong> (simple → complex):</p><ol><li>Context cards, notes, supplements — repetitive patterns, isolated</li><li>Settings, export, glossary, nav — modal-based, self-contained</li><li>Charts, views, detail modal — Chart.js integration, plugin lifecycle</li><li>Chat, pdf-import — streaming, progress bars, imperative DOM</li><li>Tour, changelog, feedback — small, low-risk</li></ol><p><strong>Workflow per module:</strong></p><ul><li>Migrate code</li><li>Subagent takes before/after screenshots (keeps main context clean)</li><li>Subagent clicks through key flows, reports pass/fail</li><li>Commit</li><li>User does quick sanity check</li></ul><p><strong>Context window strategy:</strong></p><ul><li>Screenshots go to subagents, never the main conversation</li><li>Convention doc (<code>MIGRATION.md</code>) established in session 1, read at start of each subsequent session</li><li>Git commits as checkpoints — if session breaks, read git log + existing code to rebuild context</li></ul><p><strong>Framework choice: Svelte</strong></p><ul><li>Best DX for solo maintainer (bind shortcuts, reactive stores, less boilerplate)</li><li>SvelteKit for web app (routing, static build, SSR if needed later)</li><li>First-class Tauri support</li><li>Compile-time reactivity (no virtual DOM overhead — matters for Chart.js-heavy rendering)</li></ul><h3 id="phase-4-sveltekit-web-tauri-desktop-3-5-sessions" tabindex="-1">Phase 4: SvelteKit Web + Tauri Desktop (3-5 sessions) <a class="header-anchor" href="#phase-4-sveltekit-web-tauri-desktop-3-5-sessions" aria-label="Permalink to &quot;Phase 4: SvelteKit Web + Tauri Desktop (3-5 sessions)&quot;">​</a></h3><ul><li>SvelteKit static PWA replaces vanilla JS web version</li><li>Tauri wraps same Svelte UI for desktop</li><li>GitHub Actions CI for Mac/Windows/Linux builds</li><li>Auto-updates via Tauri&#39;s built-in updater</li></ul><h3 id="phase-5-read-write-openclaw-2-3-sessions" tabindex="-1">Phase 5: Read/Write OpenClaw (2-3 sessions) <a class="header-anchor" href="#phase-5-read-write-openclaw-2-3-sessions" aria-label="Permalink to &quot;Phase 5: Read/Write OpenClaw (2-3 sessions)&quot;">​</a></h3><ul><li><strong>Read/write</strong>: user drops lab PDF in Signal/Telegram, OpenClaw runs import pipeline, saves to Evolu sync store, replies with summary</li><li>Upgrades Phase 0&#39;s read-only context gateway</li><li>OB1/Open Brain as optional cross-tool knowledge layer</li></ul><h2 id="monorepo-structure" tabindex="-1">Monorepo Structure <a class="header-anchor" href="#monorepo-structure" aria-label="Permalink to &quot;Monorepo Structure&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>packages/</span></span>
<span class="line"><span>  shared/     — TS types, schema, constants, data pipeline, Evolu sync</span></span>
<span class="line"><span>  ui/         — Svelte components (charts, modals, cards, chat)</span></span>
<span class="line"><span>  web/        — SvelteKit static PWA</span></span>
<span class="line"><span>  desktop/    — Tauri (Rust backend + same Svelte UI)</span></span></code></pre></div><h2 id="tauri-desktop-benefits" tabindex="-1">Tauri Desktop Benefits <a class="header-anchor" href="#tauri-desktop-benefits" aria-label="Permalink to &quot;Tauri Desktop Benefits&quot;">​</a></h2><ul><li>Native keychain for API keys (not localStorage)</li><li>Real filesystem backup (no File System Access API permission dance)</li><li>Direct API calls (no CORS, no proxy)</li><li>Background sync</li><li>Taskbar/dock presence, auto-updates, no browser chrome</li></ul><h2 id="v1-codebase-audit-march-2026" tabindex="-1">v1 Codebase Audit (March 2026) <a class="header-anchor" href="#v1-codebase-audit-march-2026" aria-label="Permalink to &quot;v1 Codebase Audit (March 2026)&quot;">​</a></h2><p>Comprehensive audit to inform migration scope.</p><h3 id="surface-area" tabindex="-1">Surface area <a class="header-anchor" href="#surface-area" aria-label="Permalink to &quot;Surface area&quot;">​</a></h3><ul><li>35 JS modules (~25K lines), 3,592-line monolithic CSS, 199-line HTML shell</li><li>28 browser-based test files (~7,500 lines)</li><li>643 functions on <code>window.*</code> across 25 modules (the #1 migration obstacle)</li><li>359 inline <code>onclick=</code> handlers in template-literal HTML</li><li>630 template-literal HTML blocks → become Svelte templates</li><li>326 scattered localStorage accesses across 21 modules (no abstraction layer)</li><li>1 circular dependency (<code>profile.js</code> ↔ <code>crypto.js</code>), 1 duplicated function (<code>_getCyclePhase</code>)</li><li>4 independent modal/overlay implementations → unify into <code>&lt;Modal&gt;</code> component</li></ul><h3 id="complexity-hotspots" tabindex="-1">Complexity hotspots <a class="header-anchor" href="#complexity-hotspots" aria-label="Permalink to &quot;Complexity hotspots&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Module</th><th>Lines</th><th>Window exports</th><th>Notes</th></tr></thead><tbody><tr><td><code>chat.js</code></td><td>4,062</td><td>100</td><td>Streaming, threads, markdown, onboarding, personalities — needs 5-8 components</td></tr><tr><td><code>views.js</code></td><td>2,051</td><td>53</td><td>Dashboard, charts, tables, heatmap, detail modal, manual entry, correlations</td></tr><tr><td><code>pdf-import.js</code></td><td>1,777</td><td>26</td><td>AI pipeline, batch, preview, progress — imperative DOM-heavy</td></tr><tr><td><code>settings.js</code></td><td>1,654</td><td>61</td><td>Tabs, 4 provider panels, privacy, sync, encryption</td></tr><tr><td><code>crypto.js</code></td><td>1,329</td><td>32</td><td>AES-GCM, backup/restore, folder backup, cross-tab sync</td></tr><tr><td><code>context-cards.js</code></td><td>1,270</td><td>70</td><td>9 card editors, health dots, tag pills, autocomplete</td></tr></tbody></table><h3 id="what-migrates-easily" tabindex="-1">What migrates easily <a class="header-anchor" href="#what-migrates-easily" aria-label="Permalink to &quot;What migrates easily&quot;">​</a></h3><ul><li>Pure data/logic modules (~3,200 lines: state, utils, schema, constants, adapters, hardware, image-utils, food-contaminants, supplement-warnings) — zero DOM, trivial <code>.js</code> → <code>.ts</code></li><li>CSS design tokens (33 vars, clean dark/light) — preserve as global <code>theme.css</code></li><li>CSS prefix convention (<code>chat-*</code>, <code>cl-*</code>, <code>emf-*</code>, <code>ctx-*</code>) already maps to component boundaries</li><li>Vendor deps: Chart.js, pdf.js, fonts → npm. Evolu needs WASM/COOP config spike</li></ul><h3 id="test-gaps-verify-migration-parity" tabindex="-1">Test gaps (verify migration parity) <a class="header-anchor" href="#test-gaps-verify-migration-parity" aria-label="Permalink to &quot;Test gaps (verify migration parity)&quot;">​</a></h3><p>No dedicated tests for: <code>views.js</code> (2K lines), <code>data.js</code>, <code>settings.js</code>, <code>context-cards.js</code>, <code>export.js</code>, <code>nav.js</code>, <code>profile.js</code>, <code>adapters.js</code></p><h3 id="issues-solved-by-v2-data-model" tabindex="-1">Issues solved by v2 data model <a class="header-anchor" href="#issues-solved-by-v2-data-model" aria-label="Permalink to &quot;Issues solved by v2 data model&quot;">​</a></h3><ul><li><strong>#39</strong> — per-import provenance and selective deletion (blocked by v1&#39;s date-merge model)</li><li><strong>#57</strong> — marker category reassignment without breaking history (blocked by v1&#39;s <code>category.marker</code> key format)</li></ul><h2 id="risk-assessment" tabindex="-1">Risk Assessment <a class="header-anchor" href="#risk-assessment" aria-label="Permalink to &quot;Risk Assessment&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Risk</th><th>Severity</th><th>Mitigation</th></tr></thead><tbody><tr><td>Evolu data model redesign (nested → relational)</td><td>High</td><td>Spike in Phase 2c, prove round-trip before touching UI</td></tr><tr><td>643 window globals + 359 inline onclick handlers</td><td>High</td><td>Module-by-module conversion, no incremental path</td></tr><tr><td>chat.js decomposition (4K lines, 100 exports)</td><td>Medium-High</td><td>Split into 5-8 Svelte components, keep streaming imperative</td></tr><tr><td>Evolu WASM in Vite (SharedArrayBuffer, COOP/COEP)</td><td>Medium</td><td>Build config spike early in Phase 2a</td></tr><tr><td>Test harness rewrite (current tests assume window globals)</td><td>Medium</td><td>New strategy: Vitest + Svelte component tests</td></tr><tr><td>Chart.js + Svelte lifecycle</td><td>Medium</td><td>Wrap in action/component, test resize/destroy carefully</td></tr><tr><td>Streaming chat in Svelte</td><td>Medium</td><td>Keep imperative reader loop, update Svelte store on chunks</td></tr><tr><td>Context window exhaustion</td><td>Medium</td><td>Subagents for screenshots, convention doc, git checkpoints</td></tr><tr><td>Session breaks mid-migration</td><td>Low</td><td>Each module is a commit, MIGRATION.md carries context</td></tr><tr><td>CSS migration</td><td>Low</td><td>Global styles carry over, scoped per-component</td></tr></tbody></table><h2 id="when-to-start" tabindex="-1">When to Start <a class="header-anchor" href="#when-to-start" aria-label="Permalink to &quot;When to Start&quot;">​</a></h2><p>v1 vanilla JS app is the working prototype and daily driver. Every feature shipped now teaches what the real data flow should be. Start v2 when blocked by the architecture, not when bored with it.</p>`,52)])])}const m=t(i,[["render",r]]);export{u as __pageData,m as default};
